// unaryInterceptor provides logging and basic security checks for all RPCs
func unaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	// Log the request (without sensitive content)
	log.Printf("INFO: RPC call to %s", info.FullMethod)

	start := time.Now()
	resp, err := handler(ctx, req)
	duration := time.Since(start)

	if err != nil {
		log.Printf("INFO: RPC %s failed after %v: %v", info.FullMethod, duration, err)
	} else {
		log.Printf("INFO: RPC %s completed in %v", info.FullMethod, duration)
	}

	return resp, err
}

